mapper.update:
UPDATE sys_office
SET priority = #{priority}
WHERE id = #{id}

UPDATE sys_office
SET lft = #{node.lft},
    rgt = #{node.rgt}
WHERE id = #{node.id}

UPDATE sys_office
SET parent_id = #{node.parentId}
WHERE id = #{node.id}

UPDATE sys_office
SET rgt = rgt + #{offset}
WHERE rgt >= #{from}

UPDATE sys_office
SET lft = lft + #{offset}
WHERE lft >= #{from}

UPDATE sys_office
SET lft = lft + #{offset},
    rgt = rgt + #{offset}
WHERE lft BETWEEN #{from} AND #{to}
